CREATE TABLE fiscal.collection_links(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id uuid NOT NULL,obligation_id uuid NOT NULL REFERENCES fiscal.financial_obligations(id),token_sha256 char(64) NOT NULL UNIQUE,bank_name text NOT NULL,account_type text NOT NULL,account_number_masked text NOT NULL,account_holder text NOT NULL,expires_at timestamptz NOT NULL,revoked_at timestamptz,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE fiscal.payment_proofs(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id uuid NOT NULL,collection_link_id uuid NOT NULL REFERENCES fiscal.collection_links(id),file_name text NOT NULL,mime_type text NOT NULL,content_sha256 char(64) NOT NULL,storage_ref text NOT NULL,declared_amount bigint NOT NULL CHECK(declared_amount>0),payer_note text,uploaded_at timestamptz NOT NULL DEFAULT now(),UNIQUE(collection_link_id,content_sha256));
ALTER TABLE fiscal.collection_links ENABLE ROW LEVEL SECURITY;ALTER TABLE fiscal.payment_proofs ENABLE ROW LEVEL SECURITY;REVOKE ALL ON fiscal.collection_links,fiscal.payment_proofs FROM anon,authenticated;
